```typescript
export function expandKeys(keys: string[]): string[] {
  const suffixes = [
    // Combined from all gender categories
    "e", "i", "ovi", "a", "y", "ů", "ům", "ech", "ích", "em", "ové",
    "u", "ou", "ách", "ám", "ami", "atech", "at", "atům", "aty"
  ];

  const results = new Set<string>();

  for (const rawKey of keys) {
    const key = rawKey.trim();
    if (!key) continue;

    // Always include the original key
    results.add(key);

    // Skip very short keys
    if (key.length < 3) continue;

    // For multi-word phrases, only stem the last word (noun)
    const words = key.split(/\s+/);
    const lastWord = words[words.length - 1];
    const prefix = words.length > 1 ? words.slice(0, -1).join(" ") + " " : "";

    if (lastWord.length < 3) continue;

    // Generate forms by appending suffixes to the last word
    for (const suffix of suffixes) {
      results.add(prefix + lastWord + suffix);
    }

    // Also try stripping common vowel endings for vowel-final words
    const stemmed = lastWord.replace(/(a|e|o|í|ý|á|é|ů|ě)$/u, "");
    if (stemmed && stemmed !== lastWord && stemmed.length >= 2) {
      for (const suffix of suffixes) {
        results.add(prefix + stemmed + suffix);
      }
    }
  }

  // Limit to 100
  return [...results].slice(0, 100);
}
