 * addressing pronouns ("ty"/"tobě"/"ti"/"tebe"/"tě"/"tebou"/"jí"/"mu")
 * and scans backward from the nearest pronoun for a member name.
 * Returns null when nothing is found or input is empty. */
export function findAddressedMember(
  lastAssistantText: string,
  members: SpeakerCandidate[],
): string | null {
  if (!lastAssistantText || members.length === 0) return null;

  const folded = foldForSearch(lastAssistantText);

