/** Group-chat speaker selection & message shaping (plan §3). Pure, so it's
 * unit-testable without the DB/store layer. */

import type { PromptMessage } from "../prompt/promptBuilder";
import { foldForSearch } from "./searchSnippet";

export interface SpeakerCandidate {
  id: string;
  name: string;
  position: number;
}

/** Scans `lastAssistantText` for member names (fold-insensitive). The
 * last-mentioned member is likely being addressed or prompted to speak
 * next by the AI. If no explicit name is found, looks for Czech
 * addressing pronouns ("ty"/"tobě"/"ti"/"tebe"/"tě"/"tebou"/"jí"/"mu")
 * and scans backward from the nearest pronoun for a member name.
 * Returns null when nothing is found or input is empty. */
export function findAddressedMember(
  lastAssistantText: string,
  members: SpeakerCandidate[],
): string | null {
  if (!lastAssistantText || members.length === 0) return null;

  const folded = foldForSearch(lastAssistantText);

  // Primary: last-mentioned member name in the assistant text.
  let mentionedId: string | null = null;
  let mentionedLastIdx = -1;
  for (const member of members) {
    const name = foldForSearch(member.name).trim();
    if (!name) continue;
    const idx = folded.lastIndexOf(name);
    if (idx > mentionedLastIdx) {
      mentionedLastIdx = idx;
      mentionedId = member.id;
    }
  }
  if (mentionedId) return mentionedId;

  // Fallback: Czech addressing pronouns → scan backward for nearest name.
  const pronouns = ["ty", "tobě", "ti", "tebe", "tě", "tebou", "jí", "mu"];
  let pronounIdx = -1;
  for (const pronoun of pronouns) {
    const idx = folded.lastIndexOf(foldForSearch(pronoun));
    if (idx > pronounIdx) pronounIdx = idx;
  }

  if (pronounIdx >= 0) {
    let closestId: string | null = null;
    let closestDist = Number.POSITIVE_INFINITY;
    for (const member of members) {
      const name = foldForSearch(member.name).trim();
      if (!name) continue;
      const before = folded.slice(0, pronounIdx);
      const idx = before.lastIndexOf(name);
      if (idx >= 0) {
        const dist = pronounIdx - idx;
        if (dist < closestDist) {
          closestDist = dist;
          closestId = member.id;
        }
      }
    }
    if (closestId) return closestId;
  }

  return null;
}

/** Picks the next auto-mode speaker (plan §1/§3):
 * 1. If one or more members are mentioned by name (fold-insensitive
 *    substring) in `lastUserText`, the one mentioned *last* wins.
 * 2. Otherwise, if `lastAssistantText` is provided, check whether the
 *    assistant addressed a specific member (same name-matching logic).
 * 3. Otherwise least-recently-spoken: members absent from
 *    `recentSpeakerIds` entirely go first (by `position`); among the
 *    rest, the one whose last occurrence in `recentSpeakerIds` has the
 *    smallest index (spoke longest ago) wins.
 * Returns null for an empty member list. */
export function pickNextSpeaker(
  members: SpeakerCandidate[],
  lastUserText: string,
  recentSpeakerIds: string[],
  lastAssistantText?: string,
): string | null {
  if (members.length === 0) return null;
  if (members.length === 1) return members[0].id;

  const folded = foldForSearch(lastUserText);
  let mentionedId: string | null = null;
  let mentionedLastIdx = -1;
  for (const member of members) {
    const name = foldForSearch(member.name).trim();
    if (!name) continue;
    const idx = folded.lastIndexOf(name);
    if (idx > mentionedLastIdx) {
      mentionedLastIdx = idx;
      mentionedId = member.id;
    }
  }
  if (mentionedId) return mentionedId;

  // New: assistant-addressed member before falling back to LRS.
  if (lastAssistantText) {
    const addressed = findAddressedMember(lastAssistantText, members);
    if (addressed) return addressed;
  }

  const neverSpoken = members.filter((m) => !recentSpeakerIds.includes(m.id));
  if (neverSpoken.length > 0) {
    return [...neverSpoken].sort((a, b) => a.position - b.position)[0].id;
  }

  // Least-recently-spoken: smallest index of the *last* occurrence in
  // recentSpeakerIds (oldest -> newest) means "spoke longest ago".
  let best: SpeakerCandidate | null = null;
  let bestLastIdx = Number.POSITIVE_INFINITY;
  for (const member of members) {
    const lastIdx = recentSpeakerIds.lastIndexOf(member.id);
    if (lastIdx < bestLastIdx) {
      bestLastIdx = lastIdx;
      best = member;
    }
  }
  return best ? best.id : members[0].id;
}

/** Strips a leading `Name:` or `**Name:**` prefix (case/diacritics
 * insensitive, matched via `foldForSearch`), including the optional space
 * after the colon. Leaves occurrences elsewhere in the text untouched. */
export function stripSpeakerPrefix(text: string, name: string): string {
  const foldedName = foldForSearch(name).trim();
  if (!foldedName) return text;

  const tryStrip = (prefixPattern: RegExp): string | null => {
    const match = prefixPattern.exec(text);
    if (!match) return null;
    const candidateName = match[1];
    if (foldForSearch(candidateName).trim() !== foldedName) return null;
    return text.slice(match[0].length);
  };

  // Bold form: **Name:** (with optional trailing space)
  const bold = tryStrip(/^\*\*([^*:\n]+):\*\*[ \t]?/);
  if (bold !== null) return bold;

  // Plain form: Name: (with optional trailing space)
  const plain = tryStrip(/^([^:\n*]+):[ \t]?/);
  if (plain !== null) return plain;

  return text;
}

/** Merges adjacent messages of the same role by joining their content with
 * "\n\n" — required before sending to providers with strict role
 * alternation (e.g. Claude), since group chats can produce back-to-back
 * assistant turns (plan: mergeConsecutiveRoles). */
export function mergeConsecutiveRoles(messages: PromptMessage[]): PromptMessage[] {
  const out: PromptMessage[] = [];
  for (const msg of messages) {
    const last = out[out.length - 1];
    if (last && last.role === msg.role) {
      last.content = `${last.content}\n\n${msg.content}`;
    } else {
      out.push({ ...msg });
    }
  }
  return out;
}

import { describe, expect, it } from "vitest";

import {
  findAddressedMember,
  mergeConsecutiveRoles,
  pickNextSpeaker,
  stripSpeakerPrefix,
  type SpeakerCandidate,
} from "./groupSpeaker";
import type { PromptMessage } from "../prompt/promptBuilder";

const MEMBERS: SpeakerCandidate[] = [
  { id: "a", name: "Anna", position: 0 },
  { id: "b", name: "Věž", position: 1 },
  { id: "c", name: "Kai", position: 2 },
];

describe("pickNextSpeaker", () => {
  it("returns null for an empty member list", () => {
    expect(pickNextSpeaker([], "hello", [])).toBeNull();
  });

  it("returns the only member for a single-member list, ignoring text/history", () => {
    const single: SpeakerCandidate[] = [{ id: "a", name: "Anna", position: 0 }];
    expect(pickNextSpeaker(single, "", [])).toBe("a");
  });

  it("matches a name mentioned without diacritics ('vez' -> 'Věž')", () => {
    expect(pickNextSpeaker(MEMBERS, "rekni to vez", [])).toBe("b");
  });

  it("picks the last-mentioned member when several are named in the text", () => {
    const text = "Anna a Kai si povidali, pak prisla Vez.";
    expect(pickNextSpeaker(MEMBERS, text, [])).toBe("b");
  });

  it("falls back to round-robin on the longest-silent member when no name is mentioned", () => {
    // a and b have spoken recently (oldest -> newest); c never spoke.
    const recent = ["a", "b", "a"];
    expect(pickNextSpeaker(MEMBERS, "no names here", recent)).toBe("c");
  });

  it("prefers never-spoken members by position when several never spoke", () => {
    const recent = ["a"]; // b and c never spoke; b has lower position
    expect(pickNextSpeaker(MEMBERS, "", recent)).toBe("b");
  });

  it("picks the member who spoke longest ago when everyone has spoken", () => {
    const recent = ["c", "a", "b", "a"]; // last occurrence indices: c=0, a=3, b=2
    expect(pickNextSpeaker(MEMBERS, "", recent)).toBe("c");
  });

  it("handles empty text by falling back to round-robin", () => {
    expect(pickNextSpeaker(MEMBERS, "", [])).toBe("a");
  });

  it("picks the member addressed by name in the last assistant text when user text has no mention", () => {
    // Assistant said "Kai se na tebe podívá" — Kai is mentioned.
    expect(pickNextSpeaker(MEMBERS, "co bude dál?", ["a", "b"], "Kai se na tebe podívá")).toBe("c");
  });

  it("ignores assistant text when user already mentioned a name (user priority)", () => {
    // Even though assistant mentioned Kai, user mentioned Anna last.
    expect(
      pickNextSpeaker(MEMBERS, "řekni to Anně", ["a", "c"], "Kai přikývl."),
    ).toBe("a");
  });

  it("falls back to LRS when assistant text has no member name", () => {
    expect(
      pickNextSpeaker(MEMBERS, "nic", ["a", "b"], "Jen ticho."),
    ).toBe("c"); // c never spoke
  });

  it("is backward-compatible when lastAssistantText is omitted", () => {
    expect(pickNextSpeaker(MEMBERS, "no names here", ["a", "b", "a"])).toBe("c");
  });
});

describe("findAddressedMember", () => {
  it("returns null for empty text", () => {
    expect(findAddressedMember("", MEMBERS)).toBeNull();
  });

  it("returns null for empty member list", () => {
    expect(findAddressedMember("Anna se směje.", [])).toBeNull();
  });

  it("returns the last-mentioned member in the assistant text", () => {
    // "Anna" appears first, "Kai" appears last.
    expect(findAddressedMember("Anna se podívala na Kaie.", MEMBERS)).toBe("c");
  });

  it("is fold/diacritics insensitive", () => {
    expect(findAddressedMember("vez se usmála.", MEMBERS)).toBe("b");
  });

  it("returns null when no member is mentioned", () => {
    expect(findAddressedMember("Nikdo tu není.", MEMBERS)).toBeNull();
  });

  it("finds a name near a Czech addressing pronoun (coreference)", () => {
    // "jí" is the pronoun, "Anny" appears before it.
    expect(findAddressedMember("Podíval se na Annu a řekl jí tajemství.", MEMBERS)).toBe("a");
  });

  it("picks the closest name before the pronoun when several appear", () => {
    // "Kai" appears closer to "ti" than "Anna".
    expect(
      findAddressedMember("Anna vešla. Kai ti něco pošeptal.", MEMBERS),
    ).toBe("c");
  });
});

describe("stripSpeakerPrefix", () => {
  it("strips a plain 'Name:' prefix", () => {
    expect(stripSpeakerPrefix("Anna: Hello there.", "Anna")).toBe("Hello there.");
  });

  it("strips a bold '**Name:**' prefix", () => {
    expect(stripSpeakerPrefix("**Anna:** Hello there.", "Anna")).toBe("Hello there.");
  });

  it("is case/diacritics insensitive when matching the prefix", () => {
    expect(stripSpeakerPrefix("VEZ: Ahoj.", "Věž")).toBe("Ahoj.");
  });

  it("does not touch an occurrence of the name in the middle of the text", () => {
    const text = "He said hello, Anna: that was odd.";
    expect(stripSpeakerPrefix(text, "Anna")).toBe(text);
  });

  it("is a no-op when the prefix belongs to a different name", () => {
    const text = "Kai: Hello there.";
    expect(stripSpeakerPrefix(text, "Anna")).toBe(text);
  });

  it("is a no-op on text with no prefix at all", () => {
    const text = "Just a plain sentence.";
    expect(stripSpeakerPrefix(text, "Anna")).toBe(text);
  });
});

describe("mergeConsecutiveRoles", () => {
  it("merges adjacent same-role messages by joining content with \\n\\n", () => {
    const input: PromptMessage[] = [
