/** Scans `lastAssistantText` for member names (fold-insensitive). The
 * last-mentioned member is likely being addressed or prompted to speak
 * next by the AI. If no explicit name is found, looks for Czech
 * addressing pronouns ("ty"/"tobě"/"ti"/"tebe"/"tě"/"tebou"/"jí"/"mu")
 * and scans backward from the nearest pronoun for a member name.
 * Returns null when nothing is found or input is empty. */
export function findAddressedMember(
  lastAssistantText: string,
  members: SpeakerCandidate[],
): string | null {
  if (!lastAssistantText || members.length === 0) return null;

  const folded = foldForSearch(lastAssistantText);

  // Primary: last-mentioned member name in the assistant text.
  let mentionedId: string | null = null;
  let mentionedLastIdx = -1;
  for (const member of members) {
    const name = foldForSearch(member.name).trim();
    if (!name) continue;
    const idx = folded.lastIndexOf(name);
    if (idx > mentionedLastIdx) {
      mentionedLastIdx = idx;
      mentionedId = member.id;
    }
  }
  if (mentionedId) return mentionedId;

  // Fallback: Czech addressing pronouns → scan backward for nearest name.
  const pronouns = ["ty", "tobě", "ti", "tebe", "tě", "tebou", "jí", "mu"];
  let pronounIdx = -1;
  for (const pronoun of pronouns) {
    const idx = folded.lastIndexOf(foldForSearch(pronoun));
    if (idx > pronounIdx) pronounIdx = idx;
  }

  if (pronounIdx >= 0) {
    let closestId: string | null = null;
    let closestDist = Number.POSITIVE_INFINITY;
    for (const member of members) {
      const name = foldForSearch(member.name).trim();
      if (!name) continue;
      const before = folded.slice(0, pronounIdx);
      const idx = before.lastIndexOf(name);
      if (idx >= 0) {
        const dist = pronounIdx - idx;
        if (dist < closestDist) {
          closestDist = dist;
          closestId = member.id;
        }
      }
    }
    if (closestId) return closestId;
  }

  return null;
}

