/** Memory engine orchestration (plan §6.3): decides *when* to run an
 * extraction/summarization pass and makes sure at most one job runs per
 * chat at a time. The actual LLM work lives in `extractor.ts` /
 * `summarizer.ts`; both already swallow their own errors, so a failure
 * here never surfaces to the chat UI — it's logged and simply retried the
 * next time `scheduleMemoryWork` is called (next assistant message). */

import { getConnection } from "../db/repositories/connectionsRepo";
import {
  getChat,
  setLastExtractedMessageId,
  setLastSummarizedMessageId,
} from "../db/repositories/chatsRepo";
import { listChatMembers } from "../db/repositories/chatMembersRepo";
import { getCharacter } from "../db/repositories/charactersRepo";
import { listMessages, type Message } from "../db/repositories/messagesRepo";
import { getSetting } from "../db/repositories/settingsRepo";
import type { ConnectionConfig } from "../providers/types";
import { DEFAULT_VERBATIM_WINDOW } from "../prompt/promptBuilder";
import { listActivatableEntriesForMembers } from "../db/repositories/lorebooksRepo";
import {
  syncFactEmbeddings,
  syncLoreEmbeddings,
  syncMessageChunkEmbeddings,
} from "./embeddingsEngine";
import { runExtraction, type TranscriptChatMessage } from "./extractor";
import { runSummarization, type TranscriptMessage } from "./summarizer";

export const DEFAULT_EXTRACTION_INTERVAL = 10;
/** How many messages must have scrolled past the verbatim window,
 * unsummarized, before a summarization pass is queued. Fixed per plan
 * §6.3 (only the extraction interval and verbatim window are settings). */
export const SUMMARIZE_TRIGGER_THRESHOLD = 10;

interface QueueEntry {
  running: boolean;
  pendingRerun: boolean;
}

const queues = new Map<string, QueueEntry>();

/** Maps messages to transcript entries for the extractor, stamping
 * `speakerName` from `Message.characterId` via a chatId->name lookup built
 * once per pass (plan §M10) — solo chats get an empty map and every message
 * falls back to the "AI"/"Hráč" label as before. */
function toApiMessages(messages: Message[], memberNames: Map<string, string>): TranscriptChatMessage[] {
  return messages
    .filter((m) => m.role === "user" || m.role === "assistant")
    .map((m) => ({
      role: m.role,
      content: m.content,
      speakerName: m.characterId ? (memberNames.get(m.characterId) ?? null) : null,
    }));
}

/** Same speaker-name stamping for the summarizer's `Message[]`-shaped
 * input. */
function withSpeakerNames(messages: Message[], memberNames: Map<string, string>): TranscriptMessage[] {
  return messages.map((m) => ({
    ...m,
    speakerName: m.characterId ? (memberNames.get(m.characterId) ?? null) : null,
  }));
}

async function readNumberSetting(key: string, fallback: number): Promise<number> {
  const raw = await getSetting(key);
  const parsed = raw ? Number(raw) : NaN;
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

async function resolveExtractionConnection(
  extractionConnectionId: string | null,
  connectionId: string | null,
): Promise<ConnectionConfig | null> {
  const id = extractionConnectionId ?? connectionId;
  if (!id) return null;
  return getConnection(id);
}

/** One pass of "check both triggers and run whatever's due". Re-reads
 * fresh state from the DB every time it's invoked, so it's naturally
 * idempotent — running it twice in a row when nothing changed is a no-op
 * the second time. */
async function runDueWork(chatId: string): Promise<void> {
  const chat = await getChat(chatId);
  if (!chat) return;
  const messages = await listMessages(chatId);
  if (messages.length === 0) return;

  const [extractionInterval, verbatimWindow, members] = await Promise.all([
    readNumberSetting("extraction_interval", DEFAULT_EXTRACTION_INTERVAL),
    readNumberSetting("verbatim_window", DEFAULT_VERBATIM_WINDOW),
    listChatMembers(chatId),
  ]);
  const memberCharacterIds = members.map((m) => m.characterId);
  // Built once per pass (not per message) — used to stamp speaker names on
  // the extraction/summarization transcripts (plan §M10).
  const memberNames = new Map<string, string>();
  await Promise.all(
    members.map(async (m) => {
      const character = await getCharacter(m.characterId);
      if (character) memberNames.set(m.characterId, character.name);
    }),
  );

  // --- Extraction: messages since last_extracted_message_id ---
  const lastExtractedIdx = chat.lastExtractedMessageId
    ? messages.findIndex((m) => m.id === chat.lastExtractedMessageId)
    : -1;
  const newSinceExtraction = messages.slice(lastExtractedIdx + 1);
  if (newSinceExtraction.length >= extractionInterval) {
    const connection = await resolveExtractionConnection(
      chat.extractionConnectionId,
      chat.connectionId,
    );
    if (connection) {
      await runExtraction(chatId, connection, toApiMessages(newSinceExtraction, memberNames));
      await setLastExtractedMessageId(chatId, messages[messages.length - 1].id);
    }
  }

  // --- Summarization: unmerged messages older than the verbatim window ---
  const lastSummarizedIdx = chat.lastSummarizedMessageId
    ? messages.findIndex((m) => m.id === chat.lastSummarizedMessageId)
    : -1;
  const foldableEnd = messages.length - verbatimWindow; // exclusive upper bound
  const toFold =
    foldableEnd > lastSummarizedIdx + 1 ? messages.slice(lastSummarizedIdx + 1, foldableEnd) : [];
  let folded: Message[] = [];
  if (toFold.length >= SUMMARIZE_TRIGGER_THRESHOLD) {
    const connection = chat.connectionId ? await getConnection(chat.connectionId) : null;
    if (connection) {
      await runSummarization(chatId, connection, withSpeakerNames(toFold, memberNames));
      await setLastSummarizedMessageId(chatId, toFold[toFold.length - 1].id);
      folded = toFold;
    }
  }

  // --- Embeddings (M7/M8) ---
  // Facts and lore sync every pass, but only call the embedding API when a
  // row is new or was edited since its last embedding — so manual edits
  // from the memory panel get picked up too. Message chunks are embedded
  // exactly once, right after their messages were folded into the summary.
  try {
    const connection = await resolveExtractionConnection(
      chat.extractionConnectionId,
      chat.connectionId,
    );
    await syncFactEmbeddings(chatId, connection);
    if (folded.length > 0) {
      await syncMessageChunkEmbeddings(chatId, connection, folded);
    }
    const loreEntries = await listActivatableEntriesForMembers(
      memberCharacterIds.length > 0 ? memberCharacterIds : [chat.characterId],
      chatId,
    );
    await syncLoreEmbeddings(connection, loreEntries);
  } catch (err) {
    console.warn("embedding sync failed", err);
  }
}

async function drainQueue(chatId: string, entry: QueueEntry): Promise<void> {
  try {
    await runDueWork(chatId);
  } catch (err) {
    // Belt and suspenders: extractor/summarizer already catch their own
    // errors, but a DB read/write here (e.g. getChat) could still throw.
    console.warn("memory engine job failed", err);
  } finally {
    entry.running = false;
    if (entry.pendingRerun) {
      entry.pendingRerun = false;
      scheduleMemoryWork(chatId);
    }
  }
}

/** Queues a "check and run due memory work" pass for a chat. Call this
 * after an assistant message is finalized (plan §6.3). Fire-and-forget by
 * design — never awaited by the chat flow, never throws, and coalesces
 * concurrent triggers into a single rerun per chat so at most one job runs
 * at a time. */
export function scheduleMemoryWork(chatId: string): void {
  const entry = queues.get(chatId) ?? { running: false, pendingRerun: false };
  queues.set(chatId, entry);

  if (entry.running) {
    entry.pendingRerun = true;
    return;
  }
  entry.running = true;
  void drainQueue(chatId, entry);
}

import { execute, query } from "../database";

interface SettingRow {
  key: string;
  value: string;
}

export async function getSetting(key: string): Promise<string | null> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings WHERE key = $1", [key]);
  return rows[0]?.value ?? null;
}

export async function setSetting(key: string, value: string): Promise<void> {
  await execute(
    `INSERT INTO settings (key, value) VALUES ($1, $2)
     ON CONFLICT (key) DO UPDATE SET value = excluded.value`,
    [key, value],
  );
}

export async function getAllSettings(): Promise<Record<string, string>> {
  const rows = await query<SettingRow>("SELECT key, value FROM settings", []);
  return Object.fromEntries(rows.map((r) => [r.key, r.value]));
}

import { execute, newId, nowIso, query } from "../database";
import type { LedgerCategory, LedgerFactLike } from "../../prompt/promptBuilder";

export type { LedgerCategory };

export interface LedgerFact extends LedgerFactLike {
  chatId: string;
  createdAt: string;
  updatedAt: string;
}

interface LedgerFactRow {
  id: string;
  chat_id: string;
  category: LedgerCategory;
  subject: string;
  fact: string;
  status: "active" | "archived";
  locked: number;
  created_at: string;
  updated_at: string;
}

function toFact(row: LedgerFactRow): LedgerFact {
  return {
    id: row.id,
    chatId: row.chat_id,
    category: row.category,
    subject: row.subject,
    fact: row.fact,
    status: row.status,
    locked: row.locked === 1,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

/** All facts for a chat (active + archived) — the memory panel's "Facts"
 * tab filters client-side. */
export async function listAllFacts(chatId: string): Promise<LedgerFact[]> {
  const rows = await query<LedgerFactRow>(
    "SELECT * FROM ledger_facts WHERE chat_id = $1 ORDER BY category ASC, subject ASC",
    [chatId],
  );
  return rows.map(toFact);
}

/** Only `status = 'active'` facts — what PromptBuilder consumes. */
export async function listActiveFacts(chatId: string): Promise<LedgerFact[]> {
  const rows = await query<LedgerFactRow>(
    "SELECT * FROM ledger_facts WHERE chat_id = $1 AND status = 'active' ORDER BY category ASC, subject ASC",
    [chatId],
  );
  return rows.map(toFact);
}

export interface LedgerFactDraft {
  category: LedgerCategory;
  subject: string;
  fact: string;
  locked?: boolean;
}

/** Manual create from the memory panel — fails (unique constraint) if a
 * fact with the same (chatId, category, subject) already exists; callers
 * should use `upsertFact` from the extractor merge path instead. */
export async function createFact(chatId: string, draft: LedgerFactDraft): Promise<LedgerFact> {
  const id = newId();
  const now = nowIso();
  await execute(
    `INSERT INTO ledger_facts (id, chat_id, category, subject, fact, status, locked, created_at, updated_at)
     VALUES ($1, $2, $3, $4, $5, 'active', $6, $7, $7)`,
    [id, chatId, draft.category, draft.subject, draft.fact, draft.locked ? 1 : 0, now],
  );
  return {
    id,
    chatId,
    category: draft.category,
    subject: draft.subject,
    fact: draft.fact,
    status: "active",
    locked: !!draft.locked,
    createdAt: now,
    updatedAt: now,
  };
}

export interface LedgerFactUpdate {
  category: LedgerCategory;
  subject: string;
  fact: string;
}

/** Manual edit from the memory panel. Does not touch `locked` — use
 * `setFactLocked` for that (keeps intent explicit in the UI). */
export async function updateFact(id: string, patch: LedgerFactUpdate): Promise<void> {
  await execute(
    `UPDATE ledger_facts SET category = $2, subject = $3, fact = $4, updated_at = $5 WHERE id = $1`,
    [id, patch.category, patch.subject, patch.fact, nowIso()],
  );
}

export async function setFactLocked(id: string, locked: boolean): Promise<void> {
  await execute("UPDATE ledger_facts SET locked = $2, updated_at = $3 WHERE id = $1", [
    id,
    locked ? 1 : 0,
    nowIso(),
  ]);
}

export async function setFactStatus(id: string, status: "active" | "archived"): Promise<void> {
  await execute("UPDATE ledger_facts SET status = $2, updated_at = $3 WHERE id = $1", [
    id,
    status,
    nowIso(),
  ]);
}

export async function deleteFact(id: string): Promise<void> {
  await execute("DELETE FROM ledger_facts WHERE id = $1", [id]);
}

/** Fetches a single fact by (chatId, category, subject) case-insensitively
 * on subject — the identity the extractor merges against (plan §6.3). */
export async function findFactBySubject(
  chatId: string,
  category: LedgerCategory,
  subject: string,
): Promise<LedgerFact | null> {
  const rows = await query<LedgerFactRow>(
    `SELECT * FROM ledger_facts WHERE chat_id = $1 AND category = $2 AND lower(subject) = lower($3)`,
    [chatId, category, subject],
  );
  return rows[0] ? toFact(rows[0]) : null;
}

/** Applies one extractor merge action against the DB. Pure decision logic
 * lives in `memory/extractor.ts` (`decideMergeAction`, unit-tested) — this
 * is just the persistence step, kept in the repository per the app's
 * DB-access convention. */
export async function applyLedgerUpsert(
  chatId: string,
  category: LedgerCategory,
  subject: string,
  fact: string,
): Promise<void> {
  const existing = await findFactBySubject(chatId, category, subject);
  if (existing) {
    if (existing.locked) return;
    await execute(
      `UPDATE ledger_facts SET fact = $2, status = 'active', updated_at = $3 WHERE id = $1`,
      [existing.id, fact, nowIso()],
    );
    return;
  }
  await createFact(chatId, { category, subject, fact });
}

export async function applyLedgerRemove(
  chatId: string,
  category: LedgerCategory,
  subject: string,
): Promise<void> {
  const existing = await findFactBySubject(chatId, category, subject);
  if (!existing || existing.locked) return;
  await setFactStatus(existing.id, "archived");
}

import { describe, expect, it } from "vitest";

import {
  mergeExtractedFacts,
  parseExtractorOutput,
  type ExtractedFact,
  type LedgerSnapshotFact,
} from "./extractor";

describe("parseExtractorOutput", () => {
  it("parses a plain JSON array", () => {
    const raw = '[{"category":"world","subject":"Ashford","fact":"The capital.","action":"upsert"}]';
    expect(parseExtractorOutput(raw)).toEqual([
      { category: "world", subject: "Ashford", fact: "The capital.", action: "upsert" },
    ]);
  });

  it("strips ```json code fences", () => {
    const raw = '```json\n[{"category":"npc","subject":"Innkeeper","fact":"Runs the tavern.","action":"upsert"}]\n```';
    expect(parseExtractorOutput(raw)).toHaveLength(1);
  });

  it("strips plain ``` fences without a language tag", () => {
    const raw = '```\n[{"category":"npc","subject":"Innkeeper","fact":"Runs the tavern.","action":"upsert"}]\n```';
    expect(parseExtractorOutput(raw)).toHaveLength(1);
  });

  it("finds the array even with leading/trailing prose", () => {
    const raw =
      'Here is the extracted data:\n[{"category":"quest","subject":"MainQuest","fact":"Find the relic.","action":"upsert"}]\nLet me know if you need more.';
    expect(parseExtractorOutput(raw)).toHaveLength(1);
  });

  it("returns [] for unparseable input instead of throwing", () => {
    expect(parseExtractorOutput("not json at all")).toEqual([]);
    expect(parseExtractorOutput("")).toEqual([]);
    expect(parseExtractorOutput("[{broken json")).toEqual([]);
  });

  it("drops elements with an invalid category or missing fields", () => {
    const raw = JSON.stringify([
      { category: "world", subject: "Ashford", fact: "Ok.", action: "upsert" },
      { category: "bogus", subject: "X", fact: "Y", action: "upsert" },
      { category: "npc", subject: "", fact: "No subject.", action: "upsert" },
      { category: "npc", subject: "Y", fact: "Bad action.", action: "delete" },
    ]);
    const result = parseExtractorOutput(raw);
    expect(result).toEqual([{ category: "world", subject: "Ashford", fact: "Ok.", action: "upsert" }]);
  });

  it("trims subject/fact whitespace", () => {
    const raw = '[{"category":"world","subject":"  Ashford  ","fact":"  The capital.  ","action":"upsert"}]';
    expect(parseExtractorOutput(raw)[0]).toEqual({
      category: "world",
      subject: "Ashford",
      fact: "The capital.",
      action: "upsert",
    });
  });

  it("returns [] when there's no array at all", () => {
    expect(parseExtractorOutput('{"category":"world"}')).toEqual([]);
  });
});

function fact(partial: Partial<LedgerSnapshotFact> = {}): LedgerSnapshotFact {
  return {
    id: "id1",
    category: "world",
    subject: "Ashford",
    fact: "The capital.",
    status: "active",
    locked: false,
    ...partial,
  };
}

function extracted(partial: Partial<ExtractedFact> = {}): ExtractedFact {
  return { category: "world", subject: "Ashford", fact: "The capital city.", action: "upsert", ...partial };
}

describe("mergeExtractedFacts", () => {
  it("inserts a new fact that has no existing match", () => {
    const ops = mergeExtractedFacts([], [extracted({ subject: "Ashford" })]);
    expect(ops).toEqual([{ kind: "insert", category: "world", subject: "Ashford", fact: "The capital city." }]);
  });

  it("updates an existing unlocked fact on upsert", () => {
    const ops = mergeExtractedFacts([fact()], [extracted({ fact: "Updated capital info." })]);
    expect(ops).toEqual([
      { kind: "update", category: "world", subject: "Ashford", fact: "Updated capital info.", factId: "id1" },
    ]);
  });

  it("skips a locked fact on upsert instead of updating it", () => {
    const ops = mergeExtractedFacts([fact({ locked: true })], [extracted({ fact: "Drift attempt." })]);
    expect(ops).toEqual([
      {
        kind: "skip",
        category: "world",
        subject: "Ashford",
        fact: "Drift attempt.",
        factId: "id1",
        reason: "locked",
      },
    ]);
  });

  it("matches subjects case-insensitively", () => {
    const ops = mergeExtractedFacts(
      [fact({ subject: "ashford" })],
      [extracted({ subject: "ASHFORD", fact: "Case-insensitive match." })],
    );
    expect(ops[0].kind).toBe("update");
    expect(ops[0].factId).toBe("id1");
  });

  it("only matches within the same category", () => {
    const ops = mergeExtractedFacts(
      [fact({ category: "world" })],
      [extracted({ category: "npc", subject: "Ashford" })],
    );
    expect(ops[0].kind).toBe("insert");
  });

  it("archives an existing unlocked fact on remove", () => {
    const ops = mergeExtractedFacts([fact()], [extracted({ action: "remove" })]);
    expect(ops).toEqual([
      { kind: "archive", category: "world", subject: "Ashford", fact: "The capital city.", factId: "id1" },
    ]);
  });

  it("skips remove of a locked fact", () => {
    const ops = mergeExtractedFacts([fact({ locked: true })], [extracted({ action: "remove" })]);
    expect(ops[0]).toEqual({
      kind: "skip",
      category: "world",
      subject: "Ashford",
      fact: "The capital city.",
      factId: "id1",
      reason: "locked",
    });
  });

  it("skips remove of a fact that doesn't exist", () => {
    const ops = mergeExtractedFacts([], [extracted({ action: "remove" })]);
    expect(ops[0]).toEqual({
      kind: "skip",
      category: "world",
      subject: "Ashford",
      fact: "The capital city.",
      reason: "not-found",
    });
