/** Emotion state tracking (plan B5). Pure functions — no DB/Tauri
 * imports — so they're unit-testable. Tracks NPC moods as ledger facts
 * under (category="npc", sub_key="mood") and enriches PromptBuilder
 * character descriptions with current mood. */

export const MOOD_CATEGORY = "npc";
export const MOOD_SUB_KEY = "mood";

/** How many messages without reconfirmation before a mood fact is
 *  considered stale and should be archived. */
const MOOD_DECAY_MESSAGES = 10;

// ---- Mood detection -----------------------------------------------------

/** Czech emotion words mapped to their canonical mood label.
 *  Each key is the canonical mood, values are the word forms that
 *  map to it (masculine, feminine, neuter, plural, common variants). */
const MOOD_PATTERNS: Array<{ mood: string; words: string[] }> = [
  { mood: "vyděšený", words: [
    "vyděšený", "vyděšená", "vyděšené", "vyděšení", "vyděšeně",
    "vystrašený", "vystrašená", "vystrašené", "vystrašení",
    "zděšený", "zděšená", "zděšené", "zděšení",
  ]},
  { mood: "rozzlobený", words: [
    "rozzlobený", "rozzlobená", "rozzlobené", "rozzlobení",
    "rozzlobeně", "rozhněvaný", "rozhněvaná", "rozhněvané",
    "rozhněvaní", "rozhněvaně",
    "vzteklý", "vzteklá", "vzteklé", "vzteklí",
    "zuřivý", "zuřivá", "zuřivé", "zuřiví",
    "naštvaný", "naštvaná", "naštvané", "naštvaní",
  ]},
  { mood: "smutný", words: [
    "smutný", "smutná", "smutné", "smutní", "smutně",
    "zarmoucený", "zarmoucená", "zarmoucené", "zarmoucení",
    "nešťastný", "nešťastná", "nešťastné", "nešťastní",
    "sklíčený", "sklíčená", "sklíčené", "sklíčení",
  ]},
  { mood: "radostný", words: [
    "radostný", "radostná", "radostné", "radostní", "radostně",
    "veselý", "veselá", "veselé", "veselí",
    "šťastný", "šťastná", "šťastné", "šťastní",
    "nadšený", "nadšená", "nadšené", "nadšení",
  ]},
  { mood: "zmatený", words: [
    "zmatený", "zmatená", "zmatené", "zmatení", "zmateně",
    "dezorientovaný", "dezorientovaná", "dezorientované",
    "zaražený", "zaražená", "zaražené", "zaražení",
  ]},
  { mood: "klidný", words: [
    "klidný", "klidná", "klidné", "klidní", "klidně",
    "vyrovnaný", "vyrovnaná", "vyrovnané", "vyrovnaní",
    "mírumilovný", "mírumilovná", "mírumilovné",
  ]},
  { mood: "napjatý", words: [
    "napjatý", "napjatá", "napjaté", "napjatí", "napjatě",
    "nervózní", "nervózně",
    "neklidný", "neklidná", "neklidné", "neklidní",
    "rozrušený", "rozrušená", "rozrušené", "rozrušení",
  ]},
  { mood: "zamilovaný", words: [
    "zamilovaný", "zamilovaná", "zamilované", "zamilovaní", "zamilovaně",
    "okouzlený", "okouzlená", "okouzlené", "okouzlení",
  ]},
  { mood: "zvědavý", words: [
    "zvědavý", "zvědavá", "zvědavé", "zvědaví", "zvědavě",
    "zvídavý", "zvídavá", "zvídavé", "zvídaví",
  ]},
  { mood: "unavený", words: [
    "unavený", "unavená", "unavené", "unavení", "unaveně",
    "vyčerpaný", "vyčerpaná", "vyčerpané", "vyčerpaní",
    "znavený", "znavená", "znavené", "znavení",
  ]},
];

/** Scans `content` for Czech emotion words and returns the first canonical
 *  mood found, or `null` when no emotion words are detected. The search is
 *  case-insensitive and matches whole-word boundaries (captured as
 *  word-start/end markers in regex). Returns only the first match — callers
 *  that need multi-emotion detection should iterate independently. */
export function detectMood(content: string): string | null {
  if (!content) return null;
  const lower = content.toLowerCase();
  for (const pattern of MOOD_PATTERNS) {
    for (const word of pattern.words) {
      // Match whole word: word boundary or space before/after.
      if (lower.includes(word.toLowerCase())) {
        return pattern.mood;
      }
    }
  }
  return null;
}

// ---- Decay --------------------------------------------------------------

/** Returns `true` when a mood fact should be considered stale and archived.
 *  `updated_at` is the ISO-8601 timestamp of the fact's last update;
 *  `currentTime` is the caller-provided "now" (for testability);
 *  `messageAge` is how many messages ago the fact was last confirmed.
 *
 *  A mood fact decays when it is older than `MOOD_DECAY_MESSAGES` messages
 *  without reconfirmation — meaning the extractor hasn't seen the same
 *  emotion expressed recently. */
export function decayMoodFact(
  fact: { updated_at: string },
  currentTime: Date,
  messageAge: number,
): boolean {
  if (messageAge > MOOD_DECAY_MESSAGES) return true;

  // Secondary check: if the fact is very old in wall-clock time
  // (> 7 days), also decay it even if message count is low.
  try {
    const updated = new Date(fact.updated_at);
    if (isNaN(updated.getTime())) return false; // unparseable — keep
    const ageMs = currentTime.getTime() - updated.getTime();
    const sevenDaysMs = 7 * 24 * 60 * 60 * 1000;
    if (ageMs > sevenDaysMs) return true;
  } catch {
    // If we can't parse the date, don't decay — safer to keep.
    return false;
  }

  return false;
}

// ---- Mood → description for PromptBuilder -------------------------------

/** Builds a character-name → mood-description map for use in
 *  `PromptBuilder`. Each mood fact is keyed by its `subject` (character
 *  name) and the `fact` value is the mood description (e.g. "vyděšená a
 *  nedůvěřivá").
 *
 *  If multiple mood facts exist for the same character, the first one wins.
 */
export function moodDescription(
  facts: Array<{ subject: string; fact: string }>,
): Map<string, string> {
  const map = new Map<string, string>();
  for (const f of facts) {
    if (!map.has(f.subject)) {
      map.set(f.subject, f.fact);
    }
  }
  return map;
}

import { describe, expect, it } from "vitest";

import {
  MOOD_CATEGORY,
  MOOD_SUB_KEY,
  decayMoodFact,
  detectMood,
  moodDescription,
} from "./emotions";

// ---- detectMood ---------------------------------------------------------

describe("detectMood", () => {
  it("returns null for empty or non-emotional content", () => {
    expect(detectMood("")).toBeNull();
    expect(detectMood("Šel jsem do lesa a našel meč.")).toBeNull();
    expect(detectMood("12345")).toBeNull();
  });

  it("detects vyděšený and its forms", () => {
    expect(detectMood("Byl jsem vyděšený.")).toBe("vyděšený");
    expect(detectMood("Byla vyděšená a třásla se.")).toBe("vyděšený");
    expect(detectMood("Děti byly vystrašené.")).toBe("vyděšený");
    expect(detectMood("Zděšeně vykřikl.")).toBe("vyděšený");
  });

  it("detects rozzlobený and its forms", () => {
    expect(detectMood("Byl rozzlobený na celý svět.")).toBe("rozzlobený");
    expect(detectMood("Byla naštvaná a nedala to najevo.")).toBe("rozzlobený");
    expect(detectMood("Zuřivě hleděl.")).toBe("rozzlobený");
  });

  it("detects smutný and its forms", () => {
    expect(detectMood("Cítil se smutný a opuštěný.")).toBe("smutný");
    expect(detectMood("Byla nešťastná z té zprávy.")).toBe("smutný");
    expect(detectMood("Sklíčeně svěsil hlavu.")).toBe("smutný");
  });

  it("detects radostný and its forms", () => {
    expect(detectMood("Byl radostný jako dítě.")).toBe("radostný");
    expect(detectMood("Byla veselá a smála se.")).toBe("radostný");
    expect(detectMood("Nadšeně zatleskal.")).toBe("radostný");
  });

  it("detects zmatený and its forms", () => {
    expect(detectMood("Byl zmatený z té situace.")).toBe("zmatený");
    expect(detectMood("Byla zmatená a nevěděla co říct.")).toBe("zmatený");
    expect(detectMood("Dezorientovaně se rozhlížel.")).toBe("zmatený");
  });

  it("detects klidný and its forms", () => {
    expect(detectMood("Zůstal klidný i v nebezpečí.")).toBe("klidný");
    expect(detectMood("Byla vyrovnaná a nic ji nerozhodilo.")).toBe("klidný");
  });

  it("detects napjatý and its forms", () => {
    expect(detectMood("Atmosféra byla napjatá.")).toBe("napjatý");
    expect(detectMood("Byl nervózní z výsledku.")).toBe("napjatý");
    expect(detectMood("Neklidně přecházel po místnosti.")).toBe("napjatý");
  });

  it("detects zamilovaný and its forms", () => {
    expect(detectMood("Byl do ní zamilovaný.")).toBe("zamilovaný");
    expect(detectMood("Byla okouzlená jeho šarmem.")).toBe("zamilovaný");
  });

  it("detects zvědavý and its forms", () => {
    expect(detectMood("Byl zvědavý, co se stane.")).toBe("zvědavý");
    expect(detectMood("Zvídavě nakoukla dovnitř.")).toBe("zvědavý");
  });

  it("detects unavený and its forms", () => {
    expect(detectMood("Byl unavený po dlouhé cestě.")).toBe("unavený");
    expect(detectMood("Byla vyčerpaná a potřebovala spát.")).toBe("unavený");
    expect(detectMood("Znaveně si protřel oči.")).toBe("unavený");
  });

  it("is case-insensitive", () => {
    expect(detectMood("Byl VYDĚŠENÝ.")).toBe("vyděšený");
    expect(detectMood("Byla SmUtNá.")).toBe("smutný");
  });

  it("returns the first matching mood when multiple emotions appear", () => {
    // "vyděšený" is checked first in MOOD_PATTERNS order
    const text = "Byl vyděšený a pak se rozzlobil.";
    expect(detectMood(text)).toBe("vyděšený");
  });
});

// ---- decayMoodFact ------------------------------------------------------

describe("decayMoodFact", () => {
  it("returns true when messageAge exceeds the decay threshold", () => {
    const fact = { updated_at: new Date().toISOString() };
    const now = new Date();
    expect(decayMoodFact(fact, now, 11)).toBe(true);
    expect(decayMoodFact(fact, now, 20)).toBe(true);
  });

  it("returns false when messageAge is at or below the threshold", () => {
    const fact = { updated_at: new Date().toISOString() };
    const now = new Date();
    expect(decayMoodFact(fact, now, 10)).toBe(false);
    expect(decayMoodFact(fact, now, 5)).toBe(false);
    expect(decayMoodFact(fact, now, 0)).toBe(false);
  });

  it("returns true when fact is older than 7 days in wall-clock time", () => {
    const eightDaysAgo = new Date(Date.now() - 8 * 24 * 60 * 60 * 1000);
    const fact = { updated_at: eightDaysAgo.toISOString() };
    const now = new Date();
    // Even with low message count, wall-clock age triggers decay
    expect(decayMoodFact(fact, now, 1)).toBe(true);
  });

  it("returns false for unparseable timestamps (safe)", () => {
    const fact = { updated_at: "not-a-date" };
    const now = new Date();
    // messageAge is low and timestamp is unparseable → keep
    expect(decayMoodFact(fact, now, 3)).toBe(false);
  });
});

// ---- moodDescription ----------------------------------------------------

describe("moodDescription", () => {
  it("returns an empty map for empty input", () => {
    const map = moodDescription([]);
    expect(map.size).toBe(0);
  });

  it("maps character name to mood fact", () => {
    const facts = [
      { subject: "Eliška", fact: "vyděšená a nedůvěřivá" },
      { subject: "Karel", fact: "klidný a vyrovnaný" },
    ];
    const map = moodDescription(facts);
    expect(map.get("Eliška")).toBe("vyděšená a nedůvěřivá");
    expect(map.get("Karel")).toBe("klidný a vyrovnaný");
  });

  it("first fact wins for duplicates", () => {
    const facts = [
      { subject: "Eliška", fact: "vyděšená" },
      { subject: "Eliška", fact: "radostná" },
    ];
    const map = moodDescription(facts);
    expect(map.get("Eliška")).toBe("vyděšená");
  });
});

// ---- Constants ----------------------------------------------------------

describe("MOOD_CATEGORY and MOOD_SUB_KEY", () => {
  it("uses npc as the ledger category for mood facts", () => {
    expect(MOOD_CATEGORY).toBe("npc");
  });

  it("uses mood as the sub_key for mood facts", () => {
    expect(MOOD_SUB_KEY).toBe("mood");
  });
});

