+    let total: i32 = if is_fate {
+        // Fate dice: 1 -> -1, 2 -> 0, 3 -> +1
+        results.iter().map(|&v| v as i32 - 2).sum::<i32>() + roll.bonus
+    } else {
+        results.iter().map(|&v| v as i32).sum::<i32>() + roll.bonus
+    };
+
+    (results, total)
+}
