+  let i = 0;
+  while (i < messages.length) {
+    const m = messages[i];
+    const score = scores.get(m.id) ?? 0;
+
+    if (score > IMPORTANCE_THRESHOLD) {
+      const speaker = m.speakerName ?? (m.role === "assistant" ? "AI" : "Hráč");
