+      const start = i;
+      const speakers = new Set<string>();
+      while (
+        i < messages.length &&
+        (scores.get(messages[i].id) ?? 0) <= IMPORTANCE_THRESHOLD
+      ) {
+        const sp = messages[i].speakerName ?? (messages[i].role === "assistant" ? "AI" : "Hráč");
+        speakers.add(sp);
+        i++;
+      }
+      const count = i - start;
+      const speakerList = [...speakers].join(", ");
+      lines.push(
+        `[rutinní] Proběhla krátká výměna o počasí. (${speakerList} — ${count} ${count === 1 ? "zpráva" : count >= 2 && count <= 4 ? "zprávy" : "zpráv"})`,
+      );
+    }
